import { Accordion } from 'fluent-styles';

const items = [
  { id: '1', title: 'What is React?', content: 'React is a JavaScript library...' },
  { id: '2', title: 'What is TypeScript?', content: 'TypeScript is a typed superset...' },
  { id: '3', title: 'What is React Native?', content: 'React Native is a framework...' },
];

<Accordion items={items} defaultValue="1" />

import { useState } from 'react';
import { Accordion } from 'fluent-styles';

const [expanded, setExpanded] = useState('1');

<Accordion
  items={items}
  value={expanded}
  onChange={(id) => setExpanded(id as string)}
/>

import { Accordion } from 'fluent-styles';

<Accordion
  items={items}
  multiple={true}
  defaultValue={['1', '2']}
  variant="filled"
/>

